  const afterPath = await resolveDraftPath(state.task, runDir, 'phase5a');

  await Promise.all([
    readRequiredText(reviewNotesPath),
    readRequiredText(reviewDeltaPath),
    readRequiredText(beforePath),
    readRequiredText(afterPath),
  ]);
